// ==========================================
// ⚙️ SYSTEM CONFIG & API
// ==========================================
let sysConfig = JSON.parse(localStorage.getItem('sysConfig')) || { appName: "AH Procurement", logoUrl: "https://cdn-icons-png.flaticon.com/512/3135/3135695.png", dateFormat: "DD/MM/YYYY", vatEnabled: true, vatRate: 7, theme: "light" };
function setupPWA() {
  const manifest = { "name": sysConfig.appName, "short_name": sysConfig.appName, "display": "standalone", "background_color": "#ffffff", "theme_color": "#2563eb", "icons": [{ "src": sysConfig.logoUrl, "sizes": "512x512", "type": "image/png", "purpose": "any maskable" }] };
  const link = document.createElement('link'); link.rel = 'manifest'; link.href = URL.createObjectURL(new Blob([JSON.stringify(manifest)], { type: 'application/manifest+json' })); document.head.appendChild(link);
}
setupPWA();
function toggleTheme() { sysConfig.theme = sysConfig.theme === 'light' ? 'dark' : 'light'; saveConfig(); }
function applyTheme() {
  if (sysConfig.theme === 'dark') document.documentElement.classList.add('dark'); else document.documentElement.classList.remove('dark');
  const appTitle = document.getElementById('app-main-title'), appLogo = document.getElementById('app-logo');
  if(appTitle) appTitle.textContent = sysConfig.appName; if(appLogo) appLogo.src = sysConfig.logoUrl;
}
function saveConfig() { localStorage.setItem('sysConfig', JSON.stringify(sysConfig)); applyTheme(); }
applyTheme();

function toggleSidebar() { document.getElementById('sidebar').classList.toggle('-translate-x-full'); document.getElementById('sidebar-overlay').classList.toggle('hidden'); }

const API_URL = "https://script.google.com/macros/s/AKfycbzO3jL_miDgUxQc1tO7Z5AFbQIdMJkqk-HC8qO_GXp9R73iJf7dkpWqNPp-7wkiI9KX8g/exec"; // 📌 เปลี่ยนตรงนี้ด้วย
const API_KEY = "AH_ProCure_SecureKey_2026"; 
const N = n => Number(n).toLocaleString('th-TH', {minimumFractionDigits:0, maximumFractionDigits:2});
let currentUser = JSON.parse(localStorage.getItem('currentUser')) || null, prDB = [], usersDB = [], vendorDB = [], budgetDB = [], catalogDB = [], poDB = [], dashboardCharts = [];

async function callAPI(payload, loadingMsg="กำลังโหลด...") {
  showLoading(loadingMsg); payload.apiKey = API_KEY; 
  try { const response = await fetch(API_URL, { method: "POST", headers: { "Content-Type": "text/plain;charset=utf-8" }, body: JSON.stringify(payload) }); const result = await response.json(); hideLoading(); return result; } 
  catch (error) { hideLoading(); toast("เชื่อมต่อล้มเหลว", "error", "ti-wifi-off"); return { status: "error" }; }
}
async function syncData() { const res = await callAPI({ action: 'getData' }, "ซิงค์ข้อมูลล่าสุด..."); if (res.status === 'success') { prDB = res.prs || []; usersDB = res.users || []; vendorDB = res.vendors || []; budgetDB = res.budgets || []; catalogDB = res.catalog || []; poDB = res.pos || []; } }
async function checkAuth() {
  if (currentUser) {
    document.getElementById('login-screen').classList.add('hidden'); document.getElementById('app-screen').classList.remove('hidden'); setTimeout(() => document.getElementById('app-screen').classList.remove('opacity-0'), 50);
    document.getElementById('user-name-display').textContent = currentUser.name; document.getElementById('user-avatar').textContent = currentUser.name.charAt(0); document.getElementById('user-role-display').textContent = currentUser.role;
    renderSidebar(); await syncData(); go('dashboard');
  } else { document.getElementById('login-screen').classList.remove('hidden'); document.getElementById('app-screen').classList.add('hidden'); }
}
async function handleLogin(e) {
  e.preventDefault(); const res = await callAPI({ action: 'login', user: document.getElementById('username').value.trim(), pass: document.getElementById('password').value.trim() }, "ตรวจสอบบัญชี...");
  if (res.status === 'success') { localStorage.setItem('currentUser', JSON.stringify(res.user)); currentUser = res.user; toast(`ยินดีต้อนรับ ${currentUser.name}`, 'success'); checkAuth(); } else toast(res.message || "รหัสไม่ถูกต้อง", 'error', 'ti-alert-circle');
}
function handleLogout() { showConfirm('ออกจากระบบ?', 'ต้องการออกจากระบบ?', 'warning', () => { localStorage.removeItem('currentUser'); location.reload(); }); }

// ==========================================
// 🧭 NAVIGATION & UTILS
// ==========================================
const menuConfig = [{ id: 'dashboard', label: 'Dashboard', icon: 'ti-layout-dashboard', roles: ['admin', 'manager', 'director', 'ceo', 'approver', 'user'] }, { id: 'create-pr', label: 'สร้าง PR', icon: 'ti-file-plus', roles: ['admin', 'user', 'manager', 'director', 'ceo'] }, { id: 'approve', label: 'อนุมัติ PR', icon: 'ti-clipboard-check', roles: ['admin', 'approver', 'manager', 'director', 'ceo'] }, { id: 'po', label: 'สร้าง PO', icon: 'ti-file-invoice', roles: ['admin', 'approver', 'manager', 'director'] }, { id: 'tracking', label: 'ติดตามสถานะ', icon: 'ti-truck-delivery', roles: ['admin', 'approver', 'user', 'manager', 'director', 'ceo'] }, { id: 'receive', label: 'รับสินค้า (GR)', icon: 'ti-package', roles: ['admin', 'user', 'manager'] }, { id: 'export', label: 'Export รายงาน', icon: 'ti-download', roles: ['admin', 'approver', 'manager', 'director', 'ceo'] }, { id: 'vendors', label: 'Vendor Master', icon: 'ti-building-store', roles: ['admin', 'manager', 'director'] }, { id: 'budget', label: 'Budget Control', icon: 'ti-chart-pie', roles: ['admin', 'approver', 'manager', 'director', 'ceo'] }, { id: 'catalog', label: 'คลังสินค้า', icon: 'ti-search', roles: ['admin', 'user', 'manager'] }, { id: 'settings', label: 'ตั้งค่าระบบ', icon: 'ti-settings', roles: ['admin'] }];
function renderSidebar() { document.getElementById('sidebar-menu').innerHTML = menuConfig.filter(m => m.roles.includes(currentUser.role)).map(m => `<button onclick="go('${m.id}')" id="nav-${m.id}" class="nav-btn w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold text-gray-600 dark:text-gray-300 hover:bg-gray-100/50 dark:hover:bg-gray-700/50 hover:text-primary-600 dark:hover:text-primary-400 transition-all"><i class="ti ${m.icon} text-xl"></i> ${m.label}</button>`).join(''); }

function go(page) {
  document.querySelectorAll('.nav-btn').forEach(n => n.classList.remove('bg-primary-50', 'dark:bg-primary-900/30', 'text-primary-600', 'dark:text-primary-400'));
  document.getElementById('nav-' + page)?.classList.add('bg-primary-50', 'dark:bg-primary-900/30', 'text-primary-600', 'dark:text-primary-400');
  const titles = { dashboard:'Dashboard', 'create-pr':'สร้างใบขอซื้อ (PR)', approve:'อนุมัติรายการ', po:'สร้างใบสั่งซื้อ (PO)', tracking:'ติดตามสถานะ', receive:'รับสินค้า (GR)', export:'Export รายงาน', vendors:'Vendor Master', budget:'ควบคุมงบประมาณ', catalog:'คลังสินค้า', settings:'ตั้งค่าระบบ (ERP Control)' };
  document.getElementById('page-title').textContent = titles[page] || page;
  if (window.innerWidth < 1024) { document.getElementById('sidebar').classList.add('-translate-x-full'); document.getElementById('sidebar-overlay').classList.add('hidden'); }
  const c = document.getElementById('page-content');
  if(page==='dashboard') { c.innerHTML = pageDashboard(); setTimeout(renderDashboardCharts, 100); }
  else if(page==='create-pr') { c.innerHTML = pageCreatePR(); initPRForm(); } else if(page==='approve') c.innerHTML = pageApprove(); else if(page==='po') c.innerHTML = pagePO(); else if(page==='tracking') c.innerHTML = pageTracking(); else if(page==='receive') c.innerHTML = pageReceive(); else if(page==='export') c.innerHTML = pageExport(); else if(page==='vendors') c.innerHTML = pageVendors(); else if(page==='budget') c.innerHTML = pageBudget(); else if(page==='catalog') c.innerHTML = pageCatalog(); else if(page==='settings') c.innerHTML = pageSettings();
}

function toast(msg, type='success', icon='ti-circle-check') {
  const t = document.getElementById('toast'), colors = { success: 'bg-gray-800 text-white', error: 'bg-danger-600 text-white', warning: 'bg-warning-500 text-white', info: 'bg-primary-600 text-white' };
  t.className = `fixed bottom-6 right-6 px-4 py-3 rounded-2xl shadow-xl text-sm font-bold flex items-center gap-3 transition-all duration-300 z-[200] pointer-events-none ${colors[type]}`;
  document.getElementById('toast-icon').className = `ti ${icon} text-lg`; document.getElementById('toast-msg').textContent = msg;
  t.classList.remove('toast-enter'); t.classList.add('toast-active'); setTimeout(() => { t.classList.remove('toast-active'); t.classList.add('toast-enter'); }, 3000);
}
function showLoading(text) { document.getElementById('loading-text').textContent = text; document.getElementById('loading-overlay').classList.remove('hidden'); }
function hideLoading() { document.getElementById('loading-overlay').classList.add('hidden'); }

function showConfirm(title, desc, type='primary', onConfirm) {
  const modal = document.getElementById('custom-modal'), backdrop = document.getElementById('modal-backdrop'), content = document.getElementById('modal-content'), icon = document.getElementById('modal-icon'), btn = document.getElementById('modal-confirm-btn');
  document.getElementById('modal-title').textContent = title; document.getElementById('modal-desc').textContent = desc;
  icon.className = "w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 text-3xl"; btn.className = "flex-1 text-white font-bold py-3 rounded-xl shadow-md transition";
  if(type === 'warning') { icon.classList.add('bg-warning-50', 'dark:bg-warning-900/30', 'text-warning-500'); icon.innerHTML = '<i class="ti ti-alert-triangle"></i>'; btn.classList.add('bg-warning-500', 'hover:bg-warning-600'); } 
  else if(type === 'danger') { icon.classList.add('bg-danger-50', 'dark:bg-danger-900/30', 'text-danger-500'); icon.innerHTML = '<i class="ti ti-trash"></i>'; btn.classList.add('bg-danger-600', 'hover:bg-danger-700'); } 
  else { icon.classList.add('bg-primary-50', 'dark:bg-primary-900/30', 'text-primary-500'); icon.innerHTML = '<i class="ti ti-check"></i>'; btn.classList.add('bg-primary-600', 'hover:bg-primary-700'); }
  confirmCallback = onConfirm; btn.onclick = () => { closeModal(); if(confirmCallback) confirmCallback(); }; modal.classList.remove('hidden'); setTimeout(() => { backdrop.classList.remove('modal-backdrop-enter'); backdrop.classList.add('modal-backdrop-active'); content.classList.remove('modal-content-enter'); content.classList.add('modal-content-active'); }, 10);
}
function closeModal() {
  const backdrop = document.getElementById('modal-backdrop'), content = document.getElementById('modal-content');
  backdrop.classList.remove('modal-backdrop-active'); backdrop.classList.add('modal-backdrop-enter'); content.classList.remove('modal-content-active'); content.classList.add('modal-content-enter');
  setTimeout(() => { document.getElementById('custom-modal').classList.add('hidden'); }, 300);
}

function sb(status) {
  const map = { pending: { l: 'รอ ผจก. อนุมัติ', c: 'bg-warning-100 text-warning-700 dark:bg-warning-900/30 dark:text-warning-400' }, pending_manager: { l: 'รอ ผจก. อนุมัติ', c: 'bg-warning-100 text-warning-700 dark:bg-warning-900/30 dark:text-warning-400' }, pending_director: { l: 'รอ ผอ. อนุมัติ', c: 'bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400' }, pending_ceo: { l: 'รอ CEO อนุมัติ', c: 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400' }, approved: { l: 'อนุมัติแล้ว', c: 'bg-success-100 text-success-700 dark:bg-success-900/30 dark:text-success-400' }, rejected: { l: 'ปฏิเสธ', c: 'bg-danger-100 text-danger-600 dark:bg-danger-900/30 dark:text-danger-400' }, po_issued: { l: 'ออก PO แล้ว', c: 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-400' }, received: { l: 'รับของแล้ว', c: 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300' } };
  const s = map[status] || { l: status, c: 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300' }; return `<span class="px-2.5 py-1 rounded-md text-[11px] font-bold tracking-wide ${s.c}">${s.l}</span>`;
}

// ==========================================
// 📊 UI RENDERS (GLASSMORPHISM)
// ==========================================
function pageDashboard() {
  const pending = prDB.filter(r => r.status.includes('pending')).length, poIssued = prDB.filter(r => r.status === 'po_issued').length, totalVal = prDB.reduce((sum, r) => sum + Number(r.total), 0), recentPRs = [...prDB].reverse().slice(0, 5);
  return `<div class="animate-slide-up space-y-8 pb-10"><div class="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 mb-4"><div><h2 class="text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-primary-600 to-indigo-600 dark:from-primary-400 dark:to-indigo-400">สวัสดี, ${currentUser.name} 👋</h2><p class="text-sm text-gray-500 dark:text-gray-400 mt-1">ภาพรวมระบบจัดซื้อประจำวันที่ ${new Date().toLocaleDateString('th-TH')}</p></div><button onclick="go('create-pr')" class="bg-gradient-to-r from-primary-600 to-indigo-600 hover:from-primary-500 hover:to-indigo-500 text-white px-6 py-3 rounded-2xl text-sm font-bold shadow-lg shadow-primary-500/30 hover:-translate-y-1 transition-all flex items-center gap-2"><i class="ti ti-plus text-lg"></i> สร้างคำขอซื้อ (PR)</button></div><div class="grid grid-cols-2 md:grid-cols-4 gap-5"><div class="glass-panel rounded-3xl p-6 shadow-xl shadow-gray-200/40 dark:shadow-none hover:-translate-y-1 transition flex flex-col group"><div class="w-12 h-12 rounded-2xl bg-gray-100 dark:bg-gray-700/50 text-gray-600 dark:text-gray-300 flex items-center justify-center text-2xl mb-4 group-hover:scale-110 transition"><i class="ti ti-files"></i></div><div><p class="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">PR ทั้งหมด</p><h4 class="text-3xl font-black text-gray-800 dark:text-white">${prDB.length}</h4></div></div><div class="glass-panel rounded-3xl p-6 shadow-xl shadow-warning-200/40 dark:shadow-none hover:-translate-y-1 transition flex flex-col group"><div class="w-12 h-12 rounded-2xl bg-warning-50 dark:bg-warning-900/30 text-warning-500 flex items-center justify-center text-2xl mb-4 group-hover:scale-110 transition"><i class="ti ti-clock"></i></div><div><p class="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">รออนุมัติ</p><h4 class="text-3xl font-black text-warning-500">${pending}</h4></div></div><div class="glass-panel rounded-3xl p-6 shadow-xl shadow-indigo-200/40 dark:shadow-none hover:-translate-y-1 transition flex flex-col group"><div class="w-12 h-12 rounded-2xl bg-indigo-50 dark:bg-indigo-900/30 text-indigo-500 flex items-center justify-center text-2xl mb-4 group-hover:scale-110 transition"><i class="ti ti-file-export"></i></div><div><p class="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">ออก PO แล้ว</p><h4 class="text-3xl font-black text-indigo-500">${poIssued}</h4></div></div><div class="glass-panel rounded-3xl p-6 shadow-xl shadow-success-200/40 dark:shadow-none hover:-translate-y-1 transition flex flex-col relative overflow-hidden group"><div class="absolute -right-6 -top-6 w-24 h-24 bg-success-400/20 rounded-full blur-2xl"></div><div class="w-12 h-12 rounded-2xl bg-success-50 dark:bg-success-900/30 text-success-500 flex items-center justify-center text-2xl mb-4 group-hover:scale-110 transition relative z-10"><i class="ti ti-cash"></i></div><div class="relative z-10"><p class="text-xs text-gray-400 font-bold uppercase tracking-wider mb-1">มูลค่ารวม (฿)</p><h4 class="text-2xl font-black text-success-500">${N(totalVal)}</h4></div></div></div><div class="grid grid-cols-1 xl:grid-cols-3 gap-6"><div class="xl:col-span-2 space-y-6"><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none overflow-hidden border border-white/40 dark:border-gray-700/50"><div class="p-6 border-b border-gray-100/50 dark:border-gray-700/50 flex justify-between items-center bg-white/30 dark:bg-gray-800/30"><h3 class="font-bold text-gray-800 dark:text-white flex items-center gap-2"><i class="ti ti-list text-primary-500 text-xl"></i> รายการขอล่าสุด</h3><button onclick="go('tracking')" class="text-xs font-bold text-primary-600 dark:text-primary-400 hover:text-primary-700 bg-primary-50 dark:bg-primary-900/30 px-3 py-1.5 rounded-full transition">ดูทั้งหมด</button></div><div class="overflow-x-auto p-2"><table class="min-w-full text-left text-sm"><thead class="text-gray-400 text-xs uppercase tracking-wider"><tr><th class="p-4 font-semibold">เลขที่</th><th class="p-4 font-semibold">รายการ</th><th class="p-4 text-right font-semibold">ยอดสุทธิ</th><th class="p-4 text-center font-semibold">สถานะ</th></tr></thead><tbody class="divide-y divide-gray-100/50 dark:divide-gray-700/50">${recentPRs.length > 0 ? recentPRs.map(r => `<tr class="hover:bg-gray-50/50 dark:hover:bg-gray-700/30 transition rounded-xl"><td class="p-4 font-bold text-primary-600 dark:text-primary-400">${r.id}</td><td class="p-4"><p class="text-gray-800 dark:text-gray-200 font-medium truncate w-40 md:w-auto">${r.items[0].name}</p><p class="text-[10px] text-gray-400 mt-0.5"><i class="ti ti-user"></i> ${r.req}</p></td><td class="p-4 text-right font-bold text-gray-700 dark:text-gray-300">฿${N(r.total)}</td><td class="p-4 text-center">${sb(r.status)}</td></tr>`).join('') : `<tr><td colspan="4" class="p-10 text-center text-gray-400">ยังไม่มีรายการ</td></tr>`}</tbody></table></div></div><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none p-6 border border-white/40 dark:border-gray-700/50"><h3 class="font-bold text-gray-800 dark:text-white flex items-center gap-2 mb-6"><i class="ti ti-chart-bar text-primary-500 text-xl"></i> มูลค่าสั่งซื้อแยกตามแผนก</h3><div class="relative w-full h-64"><canvas id="spendChart"></canvas></div></div></div><div class="xl:col-span-1 glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none p-6 border border-white/40 dark:border-gray-700/50 flex flex-col"><h3 class="font-bold text-gray-800 dark:text-white flex items-center gap-2 mb-6"><i class="ti ti-chart-pie text-rose-500 text-xl"></i> สัดส่วนการใช้งบ</h3><div class="relative w-full flex-1 min-h-[250px] flex items-center justify-center"><canvas id="budgetChart"></canvas></div><button onclick="go('budget')" class="w-full mt-8 bg-gray-100/50 dark:bg-gray-700/50 hover:bg-primary-50 dark:hover:bg-primary-900/30 hover:text-primary-600 text-gray-600 dark:text-gray-300 text-sm font-bold py-3 rounded-2xl transition border border-gray-200 dark:border-gray-600">ดูงบประมาณทั้งหมด</button></div></div></div>`;
}

function renderDashboardCharts() {
  dashboardCharts.forEach(c => c.destroy()); dashboardCharts = []; Chart.defaults.font.family = "'Prompt', sans-serif"; Chart.defaults.color = sysConfig.theme === 'dark' ? '#9ca3af' : '#6b7280';
  const ctxBudget = document.getElementById('budgetChart');
  if(ctxBudget && budgetDB.length > 0) dashboardCharts.push(new Chart(ctxBudget, { type: 'doughnut', data: { labels: budgetDB.map(b=>`แผนก ${b.dept}`), datasets: [{ data: budgetDB.map(b=>b.used), backgroundColor: ['#3b82f6', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6'], borderWidth: 0, hoverOffset: 4 }] }, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { usePointStyle: true, padding: 20 } } }, cutout: '70%' } }));
  const ctxSpend = document.getElementById('spendChart');
  if(ctxSpend) { const spendByDept = {}; prDB.filter(r => ['approved', 'po_issued', 'received'].includes(r.status)).forEach(r => { spendByDept[r.dept] = (spendByDept[r.dept] || 0) + Number(r.total); }); dashboardCharts.push(new Chart(ctxSpend, { type: 'bar', data: { labels: Object.keys(spendByDept).length ? Object.keys(spendByDept) : ['ไม่มีข้อมูล'], datasets: [{ label: 'มูลค่า (฿)', data: Object.keys(spendByDept).length ? Object.values(spendByDept) : [0], backgroundColor: '#6366f1', borderRadius: 6 }] }, options: { responsive: true, maintainAspectRatio: false, scales: { y: { beginAtZero: true, grid: { color: sysConfig.theme === 'dark' ? '#374151' : '#e5e7eb' } }, x: { grid: { display: false } } }, plugins: { legend: { display: false } } } })); }
}

let prItemsList = []; let prAttachment = null;
function initPRForm() { prItemsList = [{ name: '', unit: 'ชิ้น', qty: 1, price: 0 }]; prAttachment = null; renderPRTable(); }
function handleFileSelect(event) {
  const file = event.target.files[0]; if (!file) return; if (file.size > 5 * 1024 * 1024) { event.target.value = ""; return toast('ไฟล์ต้องไม่เกิน 5MB', 'warning'); }
  const reader = new FileReader(); reader.onload = e => { prAttachment = { name: file.name, mimeType: file.type, base64: e.target.result.split(',')[1] }; document.getElementById('file-name-display').textContent = file.name; document.getElementById('file-name-display').classList.add('text-primary-600', 'font-medium'); }; reader.readAsDataURL(file);
}
function renderPRTable() {
  const container = document.getElementById('pr-items-container'); if(!container) return;
  container.innerHTML = prItemsList.map((it, i) => `
    <div class="relative bg-white/50 dark:bg-gray-800/50 md:bg-transparent p-4 md:p-0 rounded-2xl md:rounded-none border border-white/40 dark:border-gray-700/50 md:border-none mb-4 md:mb-3 flex flex-col md:grid md:grid-cols-12 gap-3 items-center group">
      <div class="hidden md:block col-span-1 text-center text-sm font-bold text-gray-400">${i + 1}</div>
      <div class="md:col-span-4 w-full relative"><label class="md:hidden text-[10px] font-bold text-gray-400 uppercase bg-transparent absolute -top-2 left-2 px-1">ชื่อสินค้า</label><input type="text" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-primary-500 shadow-sm" placeholder="ชื่อสินค้า/บริการ" value="${it.name}" oninput="prItemsList[${i}].name=this.value"></div>
      <div class="flex gap-3 w-full md:contents">
        <div class="flex-1 md:col-span-2 relative"><label class="md:hidden text-[10px] font-bold text-gray-400 uppercase bg-transparent absolute -top-2 left-2 px-1">จำนวน</label><input type="number" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-primary-500 text-center shadow-sm" placeholder="0" min="1" value="${it.qty}" oninput="prItemsList[${i}].qty=+this.value; calculatePRTotal()"></div>
        <div class="flex-1 md:col-span-2 relative"><label class="md:hidden text-[10px] font-bold text-gray-400 uppercase bg-transparent absolute -top-2 left-2 px-1">หน่วย</label><input type="text" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-primary-500 text-center shadow-sm" placeholder="หน่วย" value="${it.unit}" oninput="prItemsList[${i}].unit=this.value"></div>
      </div>
      <div class="flex gap-3 w-full md:contents items-center mt-2 md:mt-0">
        <div class="flex-1 md:col-span-2 relative"><label class="md:hidden text-[10px] font-bold text-gray-400 uppercase bg-transparent absolute -top-2 left-2 px-1">ราคา/หน่วย</label><input type="number" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-2.5 outline-none focus:border-primary-500 text-right shadow-sm" placeholder="0.00" min="0" value="${it.price}" oninput="prItemsList[${i}].price=+this.value; calculatePRTotal()"></div>
        <div class="md:col-span-1 text-right md:text-center shrink-0"><button onclick="removePRItem(${i})" class="text-red-400 hover:text-red-600 transition p-2.5 rounded-xl bg-red-50 md:bg-transparent dark:bg-red-900/20 dark:md:bg-transparent" title="ลบรายการ"><i class="ti ti-trash text-lg"></i><span class="md:hidden ml-1 text-sm font-bold">ลบ</span></button></div>
      </div>
    </div>`).join('');
  calculatePRTotal();
}
function addPRItem() { prItemsList.push({ name: '', unit: 'ชิ้น', qty: 1, price: 0 }); renderPRTable(); }
function removePRItem(i) { if(prItemsList.length > 1) { showConfirm('ลบรายการ?', `ต้องการลบรายการที่ ${i+1}?`, 'danger', () => { prItemsList.splice(i, 1); renderPRTable(); toast('ลบแล้ว', 'success'); }); } }
function calculatePRTotal() {
  const subtotal = prItemsList.reduce((sum, it) => sum + (it.qty * it.price), 0);
  let vat = 0, vatHtml = `<div class="flex justify-between text-sm text-gray-400 mb-3 pb-3 border-b border-gray-200 dark:border-gray-700"><span>VAT:</span> <span>ไม่มี (0%)</span></div>`;
  if (sysConfig.vatEnabled) { vat = subtotal * (sysConfig.vatRate / 100); vatHtml = `<div class="flex justify-between text-sm text-gray-500 dark:text-gray-400 mb-3 pb-3 border-b border-gray-200 dark:border-gray-700"><span>VAT ${sysConfig.vatRate}%:</span> <span>฿ ${N(vat)}</span></div>`; }
  document.getElementById('pr-total-box').innerHTML = `<div class="flex justify-between text-sm text-gray-500 dark:text-gray-400 mb-2"><span>ยอดก่อน VAT:</span> <span>฿ ${N(subtotal)}</span></div>${vatHtml}<div class="flex justify-between text-lg font-bold text-primary-700 dark:text-primary-400"><span>ยอดสุทธิ:</span> <span>฿ ${N(subtotal + vat)}</span></div>`;
}

function pageCreatePR() {
  const userOpts = usersDB.map(u => `<option value="${u.name}">`).join('');
  return `<div class="animate-slide-up space-y-6"><div class="grid grid-cols-1 xl:grid-cols-3 gap-6"><div class="xl:col-span-2 space-y-6"><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 p-8"><h3 class="font-bold text-gray-800 dark:text-white mb-6 pb-4 border-b border-gray-100 dark:border-gray-700/50 flex items-center gap-2"><i class="ti ti-file-info text-primary-600 text-xl"></i> ข้อมูลทั่วไป</h3><div class="grid grid-cols-1 md:grid-cols-3 gap-6"><div><label class="block mb-2 text-sm font-bold text-gray-500 dark:text-gray-400">ผู้บันทึก</label><input type="text" class="w-full bg-gray-100/50 dark:bg-gray-700/50 border border-gray-200/50 dark:border-gray-600 text-gray-500 dark:text-gray-400 text-sm rounded-xl px-4 py-3 cursor-not-allowed" value="${currentUser.name}" readonly></div><div><label class="block mb-2 text-sm font-bold text-gray-700 dark:text-gray-300">ผู้ขอซื้อ <span class="text-red-500">*</span></label><input type="text" id="pr-requester" list="user-list" placeholder="พิมพ์ชื่อ..." class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-3 outline-none focus:border-primary-500 shadow-sm"><datalist id="user-list">${userOpts}</datalist></div><div><label class="block mb-2 text-sm font-bold text-gray-700 dark:text-gray-300">แผนก</label><select id="pr-dept" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 text-gray-800 dark:text-white text-sm rounded-xl px-4 py-3 outline-none shadow-sm"><option>MT</option><option>IT</option><option>HR</option><option>Operation</option></select></div></div></div><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 p-8"><div class="flex justify-between items-end mb-6 pb-4 border-b border-gray-100 dark:border-gray-700/50"><h3 class="font-bold text-gray-800 dark:text-white flex items-center gap-2"><i class="ti ti-list-details text-primary-600 text-xl"></i> รายการสินค้า</h3><button onclick="addPRItem()" class="text-sm font-bold text-primary-600 bg-primary-50 dark:bg-primary-900/30 px-4 py-2 rounded-xl hover:bg-primary-100 transition shadow-sm"><i class="ti ti-plus"></i> เพิ่ม</button></div><div id="pr-items-container" class="space-y-1"></div></div></div><div class="xl:col-span-1 space-y-6"><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 p-8 sticky top-24"><h3 class="font-bold text-gray-800 dark:text-white mb-6">สรุปยอดรวม</h3><div id="pr-total-box" class="bg-white/50 dark:bg-gray-800/50 rounded-2xl p-6 mb-6 border border-white/40 dark:border-gray-600 shadow-inner"></div><div class="mb-6"><label class="block mb-2 text-sm font-bold text-gray-700 dark:text-gray-300">แนบใบเสนอราคา</label><div class="relative border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-2xl p-6 text-center hover:bg-white/50 dark:hover:bg-gray-700 cursor-pointer transition" onclick="document.getElementById('pr-file-upload').click()"><i class="ti ti-upload text-3xl text-gray-400 mb-2 block"></i><p class="text-xs font-bold text-gray-500" id="file-name-display">คลิกเพื่ออัปโหลดไฟล์</p><input type="file" id="pr-file-upload" class="hidden" accept=".pdf,image/jpeg,image/png" onchange="handleFileSelect(event)"></div></div><button onclick="showConfirm('ส่งขออนุมัติ PR?', 'ตรวจสอบความถูกต้องก่อนยืนยัน', 'primary', submitNewPR)" class="w-full bg-gradient-to-r from-primary-600 to-indigo-600 hover:from-primary-500 hover:to-indigo-500 text-white font-bold rounded-2xl py-4 shadow-lg shadow-primary-500/30 hover:-translate-y-1 transition flex justify-center items-center gap-2"><i class="ti ti-cloud-upload text-lg"></i> ส่งขออนุมัติ</button></div></div></div></div>`;
}

async function submitNewPR() {
  const reqName = document.getElementById('pr-requester').value.trim(); if (!reqName) return toast('กรุณาระบุชื่อผู้ขอซื้อ', 'warning');
  if (prItemsList.length === 0) return toast('ต้องมีสินค้า 1 รายการ', 'warning');
  for (let i = 0; i < prItemsList.length; i++) { if (!prItemsList[i].name.trim() || prItemsList[i].qty <= 0 || prItemsList[i].price < 0) return toast(`รายการที่ ${i+1} ไม่สมบูรณ์`, 'error'); }
  const newPR = { id: `PR${new Date().getFullYear().toString().slice(-2)}${String(prDB.length+1).padStart(4,'0')}`, date: new Date().toLocaleDateString('th-TH'), dept: document.getElementById('pr-dept').value, req: reqName, items: prItemsList, attachment: prAttachment, hasVat: sysConfig.vatEnabled, vatRate: sysConfig.vatRate };
  const res = await callAPI({ action: 'createPR', prData: newPR, byUser: currentUser.username }, "บันทึกข้อมูล...");
  if (res.status === 'success') { toast('สร้าง PR สำเร็จ', 'success'); await syncData(); go('tracking'); } else { toast(res.message, 'error'); }
}

function pageApprove() {
  const pending = prDB.filter(r => {
    if (['rejected', 'approved', 'po_issued', 'received'].includes(r.status)) return false;
    if (currentUser.role === 'admin') return true; 
    if ((currentUser.role === 'manager' || currentUser.role === 'approver') && (r.status === 'pending' || r.status === 'pending_manager')) return true;
    if (currentUser.role === 'director' && r.status === 'pending_director') return true;
    if (currentUser.role === 'ceo' && r.status === 'pending_ceo') return true;
    return false;
  });
  if(pending.length === 0) return `<div class="glass-panel rounded-3xl p-12 text-center text-gray-400 border border-dashed border-gray-300 dark:border-gray-700 shadow-sm"><i class="ti ti-checkbox text-6xl mb-4 text-success-400/50"></i><p class="font-bold">ไม่มีเอกสารรออนุมัติในระดับของคุณ</p></div>`;
  return `<div class="grid gap-5 animate-slide-up">` + pending.map(r => `<div class="glass-panel p-6 rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 flex flex-col md:flex-row md:justify-between items-start md:items-center gap-4 group hover:-translate-y-1 transition-transform"><div><div class="flex items-center gap-3 mb-1"><span class="font-extrabold text-lg text-transparent bg-clip-text bg-gradient-to-r from-primary-600 to-indigo-600 dark:from-primary-400 dark:to-indigo-400">${r.id}</span> ${sb(r.status)}</div><div class="text-sm font-bold text-gray-800 dark:text-gray-200 mt-2">${r.items[0].name} ${r.items.length > 1 ? `<span class="text-gray-400 font-medium">(+${r.items.length - 1} รายการ)</span>` : ''} <span class="text-primary-600 dark:text-primary-400 ml-2">฿${N(r.total)}</span></div><div class="text-xs font-medium text-gray-500 mt-1 mb-3"><i class="ti ti-calendar"></i> ${r.date} &nbsp;|&nbsp; <i class="ti ti-briefcase"></i> ${r.dept} &nbsp;|&nbsp; <i class="ti ti-user"></i> ${r.req}</div>${r.attachment ? `<a href="${r.attachment}" target="_blank" class="inline-flex items-center gap-1.5 text-xs font-bold text-primary-600 bg-white/60 dark:bg-gray-800 shadow-sm px-3 py-1.5 rounded-lg border border-primary-100 dark:border-gray-600 hover:bg-primary-50 transition"><i class="ti ti-paperclip"></i> ดูเอกสารแนบ</a>` : ``}</div><div class="flex flex-row md:flex-col gap-2 w-full md:w-auto"><button onclick="doApprove('${r.id}', 'approved')" class="flex-1 md:flex-none bg-success-500 hover:bg-success-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold shadow-md shadow-success-500/30 transition flex items-center justify-center gap-1"><i class="ti ti-check"></i> อนุมัติ</button><button onclick="doApprove('${r.id}', 'rejected')" class="flex-1 md:flex-none bg-white dark:bg-gray-700 border border-danger-200 dark:border-danger-700/50 text-danger-600 dark:text-danger-400 hover:bg-danger-50 dark:hover:bg-gray-600 px-5 py-2.5 rounded-xl text-sm font-bold transition flex items-center justify-center gap-1"><i class="ti ti-x"></i> ปฏิเสธ</button></div></div>`).join('') + `</div>`;
}
function doApprove(id, status) {
  const isApp = status === 'approved'; showConfirm(isApp ? 'ยืนยันอนุมัติ?' : 'ยืนยันปฏิเสธ?', `ต้องการ${isApp?'อนุมัติ':'ปฏิเสธ'} PR ${id}?`, isApp ? 'primary' : 'danger', async () => {
    const res = await callAPI({ action: 'updatePR', id: id, status: status, byUser: currentUser.username, role: currentUser.role }, "ประมวลผล...");
    if(res.status === 'success') { toast(res.message, 'success'); await syncData(); go('approve'); } else { toast(res.message, 'error'); }
  });
}

function pagePO() { 
  const approvedPRs = prDB.filter(r => r.status === 'approved'); let content = '';
  if(approvedPRs.length === 0) content = `<div class="glass-panel rounded-3xl p-12 text-center border border-dashed border-gray-300 dark:border-gray-700 shadow-sm"><div class="w-24 h-24 bg-indigo-50/50 dark:bg-indigo-900/30 rounded-full flex items-center justify-center mx-auto mb-4"><i class="ti ti-file-x text-5xl text-indigo-300"></i></div><h3 class="text-xl font-bold text-gray-800 dark:text-white">ไม่มีรายการพร้อมออก PO</h3></div>`;
  else content = `<div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 p-8"><p class="text-sm font-bold text-gray-500 mb-6">เลือก PR เพื่อสร้าง PO</p><div class="space-y-4 mb-8">${approvedPRs.map(r => `<label class="flex items-center gap-4 p-5 border border-white/50 dark:border-gray-600 rounded-2xl bg-white/40 dark:bg-gray-800/50 cursor-pointer hover:bg-white/80 dark:hover:bg-gray-700 transition shadow-sm"><input type="checkbox" class="po-checkbox w-6 h-6 text-indigo-600 rounded-md border-gray-300 focus:ring-indigo-500" value="${r.id}"><div class="flex-1"><div class="flex justify-between items-center mb-1"><span class="font-extrabold text-indigo-700 dark:text-indigo-400 text-lg">${r.id}</span><span class="font-black text-gray-800 dark:text-gray-200 bg-white/50 dark:bg-gray-900/50 px-3 py-1 rounded-lg">฿${N(r.total)}</span></div><div class="text-sm font-medium text-gray-600 dark:text-gray-400">${r.items[0].name} | <span class="text-xs bg-gray-200/50 dark:bg-gray-600 px-2 py-0.5 rounded ml-1">${r.dept}</span></div></div></label>`).join('')}</div><button onclick="processCreatePO()" class="w-full bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-bold rounded-2xl py-4 shadow-lg shadow-indigo-500/30 hover:-translate-y-1 transition flex justify-center items-center gap-2"><i class="ti ti-file-export text-lg"></i> สร้างเอกสาร PO</button></div>`;
  return `<div class="animate-slide-up space-y-6"><div class="bg-gradient-to-r from-indigo-600 to-purple-700 rounded-3xl shadow-lg shadow-indigo-500/20 p-8 text-white flex justify-between items-center relative overflow-hidden"><div class="relative z-10"><h2 class="text-3xl font-black mb-2 flex items-center gap-2"><i class="ti ti-file-invoice"></i> สร้างใบสั่งซื้อ (PO)</h2><p class="text-indigo-100 font-medium">รวมคำขอซื้อที่อนุมัติแล้วเป็นใบสั่งซื้อ</p></div><i class="ti ti-receipt text-9xl absolute -right-4 -bottom-8 text-white/10 rotate-12"></i></div>${content}</div>`; 
}
function processCreatePO() {
  const cbs = document.querySelectorAll('.po-checkbox:checked'); const selectedPRs = Array.from(cbs).map(cb => cb.value);
  if (selectedPRs.length === 0) return toast('กรุณาเลือก PR อย่างน้อย 1 รายการ', 'warning');
  showConfirm('สร้าง PO?', `ออก PO จาก PR ${selectedPRs.length} รายการ`, 'primary', async () => {
    const res = await callAPI({ action: 'createPO', prIds: selectedPRs, byUser: currentUser.username }, "สร้างใบสั่งซื้อ...");
    if (res.status === 'success') { toast(res.message, 'success'); await syncData(); go('po'); } else { toast(res.message, 'error'); }
  });
}

function printPO(poId) {
  const po = poDB.find(p => p.id === poId); if (!po) return toast('ไม่พบเอกสาร', 'error');
  const prIds = po.prIds.split(',').map(s => s.trim()); let itemsHtml = ''; let grandTotal = 0;
  prDB.forEach(pr => { if (prIds.includes(pr.id)) { grandTotal += Number(pr.total); pr.items.forEach(it => { itemsHtml += `<tr><td style="padding:12px; border-bottom:1px solid #e5e7eb;">${it.name}</td><td style="padding:12px; border-bottom:1px solid #e5e7eb; text-align:center;">${it.qty}</td><td style="padding:12px; border-bottom:1px solid #e5e7eb; text-align:right;">฿${N(it.price)}</td><td style="padding:12px; border-bottom:1px solid #e5e7eb; text-align:right; font-weight:bold;">฿${N(it.qty * it.price)}</td></tr>`; }); } });
  const w = window.open('', '', 'width=900,height=700');
  w.document.write(`<html><head><title>PO - ${po.id}</title><style>body{font-family:'Prompt',sans-serif; padding:50px; color:#1f2937;} table{width:100%; border-collapse:collapse; margin-top:30px; font-size:14px;} th{background:#f9fafb; padding:15px 12px; text-align:left; border-bottom:2px solid #e5e7eb; color:#4b5563; text-transform:uppercase; font-size:12px;} .header{display:flex; justify-content:space-between; align-items:flex-start; border-bottom:4px solid #4f46e5; padding-bottom:20px;} .company h1{color:#4f46e5; margin:0; font-size:28px;} .company p{margin:5px 0 0; color:#6b7280; font-size:14px;} .po-details{text-align:right;} .po-details h2{margin:0; font-size:24px; color:#111827;} .po-details p{margin:5px 0 0; font-size:14px; color:#4b5563;} .info-box{margin-top:40px; padding:20px; background:#f9fafb; border-radius:8px; display:inline-block; min-width:300px;} .info-box p{margin:5px 0; font-size:14px;} .total-box{text-align:right; margin-top:40px; font-size:24px;} .total-amount{color:#4f46e5; font-weight:900;} .signatures{margin-top:100px; display:flex; justify-content:space-around;} .sig-line{text-align:center; border-top:1px solid #9ca3af; width:250px; padding-top:10px; font-size:14px; color:#4b5563;}</style></head><body><div class="header"><div class="company"><h1>${sysConfig.appName}</h1><p>Purchase Order (ใบสั่งซื้อ)</p></div><div class="po-details"><h2>No. ${po.id}</h2><p>วันที่: ${po.date}</p></div></div><div class="info-box"><p><strong>ผู้ขาย (Vendor):</strong> ${po.vendor}</p><p><strong>อ้างอิง PR:</strong> ${po.prIds}</p></div><table><tr><th>รายละเอียดสินค้า</th><th style="text-align:center;">จำนวน</th><th style="text-align:right;">ราคา/หน่วย</th><th style="text-align:right;">รวมเป็นเงิน</th></tr>${itemsHtml}</table><div class="total-box"><strong>ยอดชำระสุทธิ: <span class="total-amount">฿${N(grandTotal)}</span></strong></div><div class="signatures"><div class="sig-line">ผู้มีอำนาจลงนาม</div><div class="sig-line">ผู้ขาย / ผู้รับใบสั่งซื้อ</div></div><script>setTimeout(()=>{window.print(); window.close();},800);</script></body></html>`);
}

function pageReceive() { 
  const pendingPOs = poDB.filter(p => p.status === 'issued'); let html = '';
  if(pendingPOs.length === 0) html = `<div class="text-center py-10 text-gray-400"><div class="w-20 h-20 bg-emerald-50 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-4"><i class="ti ti-check text-4xl text-emerald-400"></i></div><p class="font-bold text-lg">ไม่มีสินค้าค้างรับในระบบ</p></div>`;
  else html = `<div class="space-y-4 mt-6 text-left">${pendingPOs.map(po => `<div class="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/50 dark:bg-gray-800/50 p-5 rounded-2xl border border-white/60 dark:border-gray-600 shadow-sm gap-4 hover:shadow-md transition"><div><p class="font-black text-teal-600 dark:text-teal-400 text-lg mb-1">${po.id}</p><p class="text-xs font-medium text-gray-500 dark:text-gray-400 bg-white dark:bg-gray-900 px-2 py-1 rounded inline-block shadow-sm">อ้างอิง PR: ${po.prIds}</p></div><div class="flex gap-2 w-full md:w-auto"><button onclick="printPO('${po.id}')" class="flex-1 md:flex-none bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 text-gray-700 dark:text-gray-200 px-4 py-2 rounded-xl text-sm font-bold shadow-sm hover:bg-gray-50 transition flex justify-center items-center gap-1"><i class="ti ti-printer text-lg"></i> ดู PO</button><button onclick="confirmReceive('${po.id}')" class="flex-1 md:flex-none bg-gradient-to-r from-teal-500 to-emerald-500 hover:from-teal-600 hover:to-emerald-600 text-white px-5 py-2 rounded-xl text-sm font-bold shadow-md shadow-teal-500/30 transition flex justify-center items-center gap-1"><i class="ti ti-package text-lg"></i> รับของ</button></div></div>`).join('')}</div>`;
  return `<div class="animate-slide-up space-y-6"><div class="bg-gradient-to-r from-teal-500 to-emerald-600 rounded-3xl shadow-lg shadow-teal-500/20 p-8 text-white relative overflow-hidden"><div class="relative z-10"><h2 class="text-3xl font-black mb-2 flex items-center gap-2"><i class="ti ti-package"></i> บันทึกรับสินค้า (GR)</h2><p class="text-teal-100 font-medium">ตรวจรับและตัดยอดเข้าคลัง</p></div><i class="ti ti-truck-loading text-9xl absolute -right-4 -bottom-4 text-white/10 -rotate-12"></i></div><div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 p-8 text-center">${html}</div></div>`; 
}
function confirmReceive(poId) { showConfirm('ยืนยันรับของ?', `ตรวจสอบสินค้าของ ${poId} ครบถ้วนแล้ว?`, 'primary', async () => { const res = await callAPI({ action: 'receiveGoods', poId: poId, byUser: currentUser.username }, "กำลังตัดยอด..."); if (res.status === 'success') { toast(res.message, 'success'); await syncData(); go('receive'); } else { toast(res.message, 'error'); } }); }

function pageTracking() {
  const list = (currentUser.role === 'user') ? prDB.filter(r => r.req === currentUser.name) : prDB;
  return `<div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 overflow-hidden animate-slide-up"><div class="p-6 border-b border-gray-100/50 dark:border-gray-700/50 bg-white/30 dark:bg-gray-800/30"><h2 class="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2"><i class="ti ti-truck-delivery text-primary-500 text-2xl"></i> ติดตามสถานะ (Tracking)</h2></div><div class="overflow-x-auto p-2"><table class="min-w-full text-left text-sm"><thead class="text-gray-400 text-xs uppercase tracking-wider"><tr><th class="p-4 font-semibold">PR No.</th><th class="p-4 font-semibold">ข้อมูล</th><th class="p-4 text-right font-semibold">ยอดรวม</th><th class="p-4 text-center font-semibold">สถานะ</th></tr></thead><tbody class="divide-y divide-gray-100/50 dark:divide-gray-700/50">${list.reverse().map(r=>`<tr class="hover:bg-gray-50/50 dark:hover:bg-gray-700/30 transition rounded-xl"><td class="p-4 font-bold text-primary-600 dark:text-primary-400 flex items-center gap-2">${r.id} ${r.attachment ? `<a href="${r.attachment}" target="_blank" class="text-gray-400 hover:text-primary-500 bg-white dark:bg-gray-800 shadow-sm p-1.5 rounded-lg border border-gray-100 dark:border-gray-700"><i class="ti ti-paperclip"></i></a>` : ''}</td><td class="p-4"><div class="text-sm font-bold text-gray-800 dark:text-gray-200">${r.items[0].name}</div><div class="text-xs font-medium text-gray-500 mt-1"><i class="ti ti-calendar"></i> ${r.date} | <i class="ti ti-user"></i> ${r.req}</div></td><td class="p-4 text-right text-sm font-black text-gray-700 dark:text-gray-300">฿${N(r.total)}</td><td class="p-4 text-center">${sb(r.status)}</td></tr>`).join('')}</tbody></table></div></div>`;
}

function pageExport() { return `<div class="animate-slide-up space-y-6"><div class="bg-gradient-to-r from-purple-600 to-fuchsia-600 rounded-3xl shadow-lg p-8 text-white"><h2 class="text-3xl font-black mb-1"><i class="ti ti-report-analytics"></i> Export Report</h2><p class="text-purple-100">ระบบรายงานและวิเคราะห์ข้อมูล</p></div><div class="glass-panel p-12 text-center rounded-3xl border border-white/40 dark:border-gray-700/50"><i class="ti ti-file-spreadsheet text-7xl text-gray-300 dark:text-gray-600 mb-6 block"></i><h3 class="text-xl font-bold text-gray-800 dark:text-white mb-2">ระบบ Report Generator</h3><p class="text-gray-500 dark:text-gray-400">ฟีเจอร์ดาวน์โหลด Excel จะเปิดให้ใช้งานในการอัปเดตครั้งถัดไป</p></div></div>`; }
function pageVendors() { return `<div class="animate-slide-up space-y-6"><div class="flex justify-between items-center"><h2 class="text-2xl font-bold dark:text-white flex items-center gap-2"><i class="ti ti-building-store text-amber-500 text-3xl"></i> ทะเบียนผู้ขาย (Vendor)</h2></div><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">${vendorDB.map(v => `<div class="glass-panel border border-white/40 dark:border-gray-700/50 p-6 rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none hover:-translate-y-1 transition group"><div class="flex justify-between items-start mb-4"><div class="w-14 h-14 bg-gradient-to-br from-amber-400 to-orange-500 text-white rounded-2xl flex items-center justify-center font-black text-2xl shadow-md group-hover:scale-110 transition">${v.name[0]}</div><span class="bg-amber-100/50 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-xs px-3 py-1.5 rounded-lg font-bold border border-amber-200/50 dark:border-amber-800/50"><i class="ti ti-star-filled text-amber-500"></i> ${v.score}</span></div><h3 class="font-bold text-lg dark:text-white truncate">${v.name}</h3><p class="text-xs font-medium text-gray-500 mt-1 bg-white/50 dark:bg-gray-800 px-2.5 py-1 rounded inline-block">${v.cat}</p></div>`).join('')}</div></div>`; }
function pageBudget() { return `<div class="animate-slide-up space-y-6"><div class="flex justify-between items-center"><h2 class="text-2xl font-bold dark:text-white flex items-center gap-2"><i class="ti ti-chart-pie text-rose-500 text-3xl"></i> งบประมาณ (Budget)</h2></div><div class="grid grid-cols-1 md:grid-cols-2 gap-6">${budgetDB.map(b => { const pct = Math.round((b.used/b.budget)*100); return `<div class="glass-panel p-6 rounded-3xl border border-white/40 dark:border-gray-700/50 shadow-xl shadow-gray-200/30 dark:shadow-none hover:-translate-y-1 transition"><div class="flex justify-between mb-4"><h3 class="font-bold text-lg dark:text-white">แผนก ${b.dept}</h3><span class="font-black text-xl ${pct>80?'text-red-500':'text-emerald-500'}">${pct}%</span></div><div class="w-full bg-gray-200/50 dark:bg-gray-700 rounded-full h-4 mb-4 shadow-inner overflow-hidden"><div class="${pct>80?'bg-red-500':'bg-emerald-500'} h-4 rounded-full transition-all duration-1000" style="width: ${pct}%"></div></div><div class="flex justify-between text-sm font-bold text-gray-600 dark:text-gray-400"><span>ใช้: ฿${N(b.used)}</span><span>เต็ม: ฿${N(b.budget)}</span></div></div>`}).join('')}</div></div>`; }
function pageCatalog() { return `<div class="animate-slide-up space-y-6"><div class="glass-panel rounded-3xl p-8 border border-white/40 dark:border-gray-700/50 shadow-xl shadow-gray-200/30 dark:shadow-none"><h2 class="text-2xl font-bold dark:text-white mb-6 flex items-center gap-2"><i class="ti ti-search text-cyan-600"></i> คลังสินค้า (Catalog)</h2><div class="overflow-x-auto"><table class="min-w-full text-left text-sm"><thead class="bg-white/30 dark:bg-gray-800/50 text-gray-500 dark:text-gray-400 uppercase text-xs tracking-wider"><tr><th class="p-4 font-bold rounded-tl-xl rounded-bl-xl">รหัส</th><th class="p-4 font-bold">ชื่อสินค้า</th><th class="p-4 text-right font-bold rounded-tr-xl rounded-br-xl">ราคา</th></tr></thead><tbody class="divide-y divide-gray-100/50 dark:divide-gray-700/50">${catalogDB.map(c => `<tr class="dark:text-gray-200 hover:bg-gray-50/50 dark:hover:bg-gray-700/30 transition"><td class="p-4 font-black text-cyan-700 dark:text-cyan-500">${c.code}</td><td class="p-4 font-bold">${c.name}</td><td class="p-4 text-right font-bold">฿${N(c.price)}</td></tr>`).join('')}</tbody></table></div></div></div>`; }

function pageSettings() {
  const rColor = currentUser.role === 'admin' ? 'bg-purple-100 text-purple-700 border-purple-200' : 'bg-gray-100 text-gray-700 border-gray-200';
  const userTableHtml = usersDB.map(u => `<tr class="hover:bg-white/40 dark:hover:bg-gray-700/50 transition"><td class="p-4 font-bold text-gray-800 dark:text-gray-200">${u.name}</td><td class="p-4 font-medium text-gray-500 dark:text-gray-400">${u.username}</td><td class="p-4"><span class="bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-300 px-3 py-1.5 rounded-lg text-[10px] uppercase font-bold border border-gray-200 dark:border-gray-600 shadow-sm">${u.role}</span></td><td class="p-4 flex gap-2"><button onclick="openUserModal('${u.username}')" class="text-blue-500 hover:text-blue-700 transition p-2 rounded-xl bg-blue-50 dark:bg-blue-900/30 shadow-sm" title="แก้ไข"><i class="ti ti-edit text-lg"></i></button>${(u.username !== 'admin' && u.username !== currentUser.username) ? `<button onclick="deleteUser('${u.username}')" class="text-red-500 hover:text-red-700 transition p-2 rounded-xl bg-red-50 dark:bg-red-900/30 shadow-sm" title="ลบผู้ใช้"><i class="ti ti-trash text-lg"></i></button>` : `<span class="w-9"></span>`}</td></tr>`).join('');
  return `
  <div class="max-w-4xl space-y-8 animate-slide-up pb-10">
    <div class="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
      <h2 class="text-3xl font-black text-gray-800 dark:text-white flex items-center gap-3"><div class="w-12 h-12 bg-gray-800 dark:bg-white text-white dark:text-gray-800 rounded-2xl flex items-center justify-center shadow-lg"><i class="ti ti-settings text-2xl"></i></div> การตั้งค่า (ERP)</h2>
      <button onclick="toggleTheme()" class="glass-panel dark:bg-gray-800 text-gray-800 dark:text-white px-5 py-3 rounded-2xl text-sm font-bold shadow-lg hover:-translate-y-1 transition flex items-center gap-2"><i class="ti ti-${sysConfig.theme === 'dark' ? 'sun' : 'moon'} text-lg"></i> โหมดสว่าง/มืด</button>
    </div>

    <div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 overflow-hidden">
      <div class="p-6 border-b border-gray-100/50 dark:border-gray-700/50 bg-white/30 dark:bg-gray-800/30"><h3 class="font-bold text-gray-800 dark:text-white text-lg">ข้อมูลผู้ใช้งาน (Profile)</h3></div>
      <div class="p-8 flex items-center gap-6"><div class="w-24 h-24 bg-gradient-to-br from-primary-500 to-indigo-600 text-white rounded-3xl shadow-lg flex items-center justify-center text-4xl font-black">${currentUser.name.charAt(0)}</div><div><h4 class="text-2xl font-black dark:text-white mb-1">${currentUser.name}</h4><p class="text-gray-500 font-medium mb-3">${currentUser.username}</p><span class="px-4 py-1.5 rounded-xl text-xs font-bold uppercase border shadow-sm ${rColor}">${currentUser.role}</span></div></div>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
      <div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 overflow-hidden"><div class="p-6 border-b border-gray-100/50 dark:border-gray-700/50 bg-white/30 dark:bg-gray-800/30"><h3 class="font-bold text-gray-800 dark:text-white text-lg">การแสดงผล (Preferences)</h3></div><div class="p-8 space-y-5"><div><label class="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">ชื่อระบบ</label><input type="text" id="cfg-app-name" value="${sysConfig.appName}" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 dark:text-white rounded-xl px-4 py-3 text-sm outline-none shadow-sm focus:border-primary-500"></div><div><label class="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">ลิงก์โลโก้</label><input type="text" id="cfg-logo" value="${sysConfig.logoUrl}" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 dark:text-white rounded-xl px-4 py-3 text-sm outline-none shadow-sm focus:border-primary-500"></div><div class="flex gap-4"><div class="flex-1"><label class="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">ใช้งาน VAT</label><select id="cfg-vat-en" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 dark:text-white rounded-xl px-4 py-3 text-sm outline-none shadow-sm"><option value="true" ${sysConfig.vatEnabled ? 'selected' : ''}>เปิดใช้งาน</option><option value="false" ${!sysConfig.vatEnabled ? 'selected' : ''}>ปิดใช้งาน</option></select></div><div class="w-24"><label class="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">VAT (%)</label><input type="number" id="cfg-vat-rate" value="${sysConfig.vatRate}" class="w-full bg-white/80 dark:bg-gray-700 border border-gray-200/50 dark:border-gray-600 dark:text-white rounded-xl px-4 py-3 text-sm outline-none shadow-sm text-center"></div></div><button onclick="saveUIPrefs()" class="w-full bg-gray-800 dark:bg-gray-200 text-white dark:text-gray-800 font-bold py-3.5 rounded-xl mt-4 shadow-lg hover:-translate-y-1 transition">บันทึกการตั้งค่า</button></div></div>
      <div class="bg-red-50/80 dark:bg-red-900/20 rounded-3xl border border-red-200 dark:border-red-900/50 overflow-hidden h-fit shadow-lg shadow-red-500/10"><div class="p-6 border-b border-red-200/50 dark:border-red-900/50"><h3 class="font-bold text-red-700 dark:text-red-400 text-lg flex items-center gap-2"><i class="ti ti-alert-triangle text-2xl"></i> Danger Zone</h3></div><div class="p-8"><p class="text-sm font-medium text-red-600 dark:text-red-300 mb-6 leading-relaxed">รีเซ็ตข้อมูลทั้งหมดและสร้างฐานข้อมูลใหม่พร้อมกับตั้งค่าสิทธิ์ระดับ Enterprise (CEO, Director, Manager)</p><button onclick="generateMockData()" class="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-red-500/30 hover:-translate-y-1 transition">ดำเนินการรีเซ็ตฐานข้อมูล</button></div></div>
    </div>

    <div class="glass-panel rounded-3xl shadow-xl shadow-gray-200/30 dark:shadow-none border border-white/40 dark:border-gray-700/50 overflow-hidden mt-8"><div class="p-6 border-b border-gray-100/50 dark:border-gray-700/50 flex justify-between items-center bg-white/30 dark:bg-gray-800/30"><h3 class="font-bold text-gray-800 dark:text-white text-lg flex items-center gap-2"><i class="ti ti-users text-primary-500 text-2xl"></i> จัดการผู้ใช้งาน (User Management)</h3><button onclick="openUserModal()" class="bg-primary-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold shadow-lg shadow-primary-500/30 hover:-translate-y-1 transition flex items-center gap-1"><i class="ti ti-user-plus text-lg"></i> เพิ่มผู้ใช้ใหม่</button></div><div class="overflow-x-auto p-4"><table class="min-w-full text-sm text-left"><thead class="text-gray-400 uppercase tracking-wider text-xs"><tr><th class="p-4 font-semibold">ชื่อ-นามสกุล</th><th class="p-4 font-semibold">Username</th><th class="p-4 font-semibold">สิทธิ์ (Role)</th><th class="p-4 font-semibold">จัดการ</th></tr></thead><tbody class="divide-y divide-gray-100/50 dark:divide-gray-700/50">${userTableHtml}</tbody></table></div></div>
  </div>`;
}

function saveUIPrefs() { sysConfig.appName = document.getElementById('cfg-app-name').value; sysConfig.logoUrl = document.getElementById('cfg-logo').value; sysConfig.vatEnabled = document.getElementById('cfg-vat-en').value === 'true'; sysConfig.vatRate = Number(document.getElementById('cfg-vat-rate').value); saveConfig(); toast('บันทึกสำเร็จ', 'success'); }
async function generateMockData() { showConfirm('รีเซ็ตฐานข้อมูล?', 'ลบข้อมูลเดิมทั้งหมดและสร้าง DB ใหม่?', 'danger', async () => { const res = await callAPI({ action: 'initMockData' }, "ดำเนินการ..."); if (res.status === 'success') { toast(res.message, 'success'); setTimeout(() => { localStorage.removeItem('currentUser'); location.reload(); }, 1500); } else toast(res.message, 'error'); }); }

function openUserModal(username = null) {
  const modal = document.getElementById('user-modal'), title = document.getElementById('user-modal-title'), hint = document.getElementById('um-pass-hint'), un = document.getElementById('um-username');
  if (username) { const user = usersDB.find(u => u.username === username); title.innerHTML = `<i class="ti ti-user-edit text-primary-600"></i> แก้ไขผู้ใช้งาน`; hint.textContent = "(เว้นว่างเพื่อใช้รหัสเดิม)"; un.value = user.username; un.disabled = true; un.classList.add('opacity-50', 'cursor-not-allowed'); document.getElementById('um-name').value = user.name; document.getElementById('um-role').value = user.role; } 
  else { title.innerHTML = `<i class="ti ti-user-plus text-primary-600"></i> เพิ่มผู้ใช้งาน`; hint.textContent = "(ตั้งรหัสผ่านใหม่)"; un.value = ''; un.disabled = false; un.classList.remove('opacity-50', 'cursor-not-allowed'); document.getElementById('um-name').value = ''; document.getElementById('um-role').value = 'user'; }
  document.getElementById('um-password').value = ''; modal.classList.remove('hidden');
}
function closeUserModal() { document.getElementById('user-modal').classList.add('hidden'); }
async function submitUserForm() {
  const data = { username: document.getElementById('um-username').value.trim(), name: document.getElementById('um-name').value.trim(), password: document.getElementById('um-password').value, role: document.getElementById('um-role').value };
  if (!data.username || !data.name) return toast('กรุณากรอก Username และชื่อ', 'warning'); if (!document.getElementById('um-username').disabled && !data.password) return toast('ต้องกำหนดรหัสผ่าน', 'warning');
  const res = await callAPI({ action: 'saveUser', userData: data, byUser: currentUser.username }, "กำลังบันทึก...");
  if (res.status === 'success') { toast(res.message, 'success'); closeUserModal(); await syncData(); go('settings'); } else toast(res.message, 'error');
}
function deleteUser(username) { showConfirm('ลบผู้ใช้?', `ยืนยันการลบผู้ใช้ ${username}?`, 'danger', async () => { const res = await callAPI({ action: 'deleteUser', targetUsername: username, byUser: currentUser.username }, "ลบข้อมูล..."); if (res.status === 'success') { toast(res.message, 'success'); await syncData(); go('settings'); } else toast(res.message, 'error'); }); }

if (API_URL.includes("วาง_WEB_APP_URL")) alert("⚠️ ตั้งค่า API_URL ในไฟล์ script.js ก่อนใช้งาน"); else checkAuth();
